/**
 * OG Image Generator — /api/og-image
 * 1200×630 branded featured images for WordPress blog posts.
 *
 * Banner (banner-1sol.jpg) is embedded as base64 — no CDN fetch, no cache issues.
 * Overlays only the post title in bold white, centered, 200px padding each side.
 *
 * Query params:
 *   title  — blog post title (URL-encoded)
 *   secret — must match OG_SECRET env var
 */

import { ImageResponse } from 'next/og';

export const config = { runtime: 'edge' };

// Banner embedded as base64 to avoid Vercel CDN caching issues
const BANNER_DATA = 'data:image/png;base64,';

export default async function handler(req) {
  try {
    const { searchParams } = new URL(req.url);
    const title  = searchParams.get('title') || '1Solutions Blog';
    const secret = searchParams.get('secret') || '';

    // Auth check
    const expected = process.env.OG_SECRET || '';
    if (expected && secret !== expected) {
      return new Response('Unauthorized', { status: 401 });
    }

    // Clamp title
    const displayTitle = title.length > 110 ? title.slice(0, 107) + '…' : title;

    // Dynamic font size based on length
    let fontSize = 58;
    if (displayTitle.length > 80) fontSize = 42;
    else if (displayTitle.length > 55) fontSize = 50;

    // Fetch Inter Bold font only
    const fontRes = await fetch(
      'https://fonts.gstatic.com/s/inter/v13/UcCO3FwrK3iLTeHuS_fvQtMwCp50KnMw2boKoduKmMEVuFuYAZJh.woff2',
      { cache: 'force-cache' }
    );
    const fontData = fontRes.ok ? await fontRes.arrayBuffer() : null;

    const imageResponse = new ImageResponse(
      (
        <div
          style={{
            display: 'flex',
            width: '1200px',
            height: '630px',
            position: 'relative',
            overflow: 'hidden',
            fontFamily: '"Inter", "Helvetica Neue", Arial, sans-serif',
          }}
        >
          {/* Banner background (logo + branding pre-baked, embedded as base64) */}
          <img
            src={BANNER_DATA}
            style={{
              position: 'absolute', inset: 0,
              width: '1200px', height: '630px',
              objectFit: 'cover', objectPosition: 'center',
            }}
          />

          {/* Title: bold white, centered, 200px padding each side */}
          <div style={{
            position: 'absolute',
            top: 0, bottom: 0,
            left: '200px',
            width: '800px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}>
            <div style={{
              color: '#ffffff',
              fontSize: fontSize + 'px',
              fontWeight: '700',
              lineHeight: '1.25',
              letterSpacing: '-0.3px',
              width: '800px',
              textAlign: 'center',
            }}>
              {displayTitle}
            </div>
          </div>
        </div>
      ),
      {
        width: 1200,
        height: 630,
        ...(fontData ? {
          fonts: [{ name: 'Inter', data: fontData, style: 'normal', weight: 700 }],
        } : {}),
      }
    );
    imageResponse.headers.set('Cache-Control', 'no-store');
    return imageResponse;
  } catch (err) {
    return new Response('OG image error: ' + err.message, { status: 500 });
  }
}
